#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture( sampler_main, vUv ).xyz;

vec3 ret7=ret;
if(uFrame%3==0)ret.z=.71-ret7.x;

    // ERROR DIFFUSION DITHER - looks great
    vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;
    ret += (texture(sampler_noise_lq, dither_uv).xyz-0.5)/256.0*1;

if(uFrame%5==0)ret.x=.71-ret7.y;


    // mix in img...
    vec3 pic = texture(sampler_pic, vUvOriginal).xyz;
    float lum = lum(pic);
    float use_it = abs(lum - fract((audioLow+audioMid+audioHigh)*0.2));
    use_it = clamp01(1 - use_it*33);
    ret = mix(ret, pic, use_it.xxx);


if(uFrame%7==0)ret.y=.71-ret7.z;

    // darken over uTime
    //ret -= 0.004;
    //ret *= 0.99;
    ret *= 0.97 + 0.03*clamp01( length(vUv - vUvOriginal)*200 );  // center only

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uvc = vUv-.5;
vec2 uv1 = vUv-vec2(q1,q2);
vec2 uv1a= vUv-vec2(q2,q1);
vec2 uvm = vec2(atan(uvc.x,uvc.y), 1/length(uvc));
uvm=vUv;

float tun=atan(uv1a.x,uv1a.y)-12*length(uv1);
tun-=.2*q11-uTime;


vec3 blur = GetBlur1(uvm);
vec3 sharp = texture(sampler_main, uvm);
vec3 fix = GetPixel(fract(uvm));

float mod = (fix/((1)-cos(tun)));

vec3 fret = (fix-blur-sin(uTime))*mod;
vec3 inv = 1-fret;

float melt = dot(fret, inv);

ret=texture(sampler_main, vec2(vUv.x, vUv.y*.75))*inv+.55*fret;

vec3 ret7=ret;
if(uFrame%02==0)ret.x=.71-ret7.y;

ret=mix(ret, inv, 1.5*clamp01(melt));

if(uFrame%11==0)ret.y=.71-ret7.z;
if(uFrame%13==0)ret.z=.71-ret7.x;


//ret=GetPixel(vUv);

  fragColor = ret;
}
